      model: route.modelId,
      messages,
      prompt_cache_retention: promptCacheRetention,
      temperature:
        typeof providerOptions?.temperature === 'number'
          ? providerOptions.temperature
          : undefined,
      ...(reasoningEffort ? { reasoning_effort: reasoningEffort } : {}),
    });
