    if (status !== 'completed') {
      // failed / expired / canceled — surface the first error if available
      const errMsg = batch.errors?.data?.[0]?.message;
      return {
        status,
        error: errMsg,
        requestCount: counts?.total,
        completedCount: counts?.completed,
        failedCount: counts?.failed,
      };
