import { useEffect, useState } from 'react';
import { Paperclip, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

type UploadedMessage = {
  id: string;
  channelId: string;
  employeeId: string | null;
  role: 'user' | 'assistant' | 'system';
  content: string;
  createdAt: string;
  authorName: string | null;
};

export function DocumentUpload({
  channelId,
  employeeId: _employeeId,
  initialFile,
  onDone,
}: {
  channelId: string;
  employeeId: string;
  /** Pre-populate the file (e.g. from a drag-and-drop). */
  initialFile?: File | null;
  onDone: (message: UploadedMessage | null) => void;
}) {
  const [file, setFile] = useState<File | null>(initialFile ?? null);
  const [caption, setCaption] = useState('');
  const [status, setStatus] = useState<'idle' | 'uploading' | 'done' | 'error'>('idle');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Sync when a file is dropped externally (drag-to-upload from parent).
  useEffect(() => {
    if (initialFile) {
      setFile(initialFile);
      setStatus('idle');
      setErrorMsg(null);
    }
  }, [initialFile]);

  async function upload() {
    if (!file) return;
    setStatus('uploading');
    setErrorMsg(null);

    try {
      const body = new FormData();
      body.append('file', file);
      body.append('channelId', channelId);
      if (caption.trim()) body.append('caption', caption.trim());

      const res = await fetch('/api/documents', {
        method: 'POST',
        body,
